Функция ПолучитьСуммарныйДолгКонтрагента(Контрагент) Экспорт

	Запрос = Новый Запрос;
	Запрос.Текст =
	"ВЫБРАТЬ
	|	ЕСТЬNULL(СУММА(
	|		ВЫБОР
	|			КОГДА ВзаиморасчетыОстатки.СуммаОстаток > 0
	|				ТОГДА ВзаиморасчетыОстатки.СуммаОстаток
	|			ИНАЧЕ 0
	|		КОНЕЦ), 0) КАК Долг
	|ИЗ
	|	РегистрНакопления.Взаиморасчеты.Остатки(, Договор.Владелец = &Контрагент) КАК ВзаиморасчетыОстатки";

	Запрос.УстановитьПараметр("Контрагент", Контрагент);

	Выборка = Запрос.Выполнить().Выбрать();

	Если Выборка.Следующий() Тогда
		Возврат Выборка.Долг;
	КонецЕсли;

	Возврат 0;

КонецФункции
